#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeHostStoreCallback: FfiConverter {
    fileprivate static let handleMap = UniffiHandleMap<HostStoreCallback>()

    typealias FfiType = UInt64
    typealias SwiftType = HostStoreCallback

    public static func lift(_ handle: UInt64) throws -> HostStoreCallback {
        if ((handle & 1) == 0) {
            // Rust-generated handle, construct a new class that uses the handle to implement the
            // interface
            return HostStoreCallbackImpl(unsafeFromHandle: handle)
        } else {
            // Swift-generated handle, get the object from the handle map
            return try handleMap.remove(handle: handle)
        }
    }

    public static func lower(_ value: HostStoreCallback) -> UInt64 {
         if let rustImpl = value as? HostStoreCallbackImpl {
             // Rust-implemented object.  Clone the handle and return it
            return rustImpl.uniffiCloneHandle()
         } else {
            // Swift object, generate a new vtable handle and return that.
            return handleMap.insert(obj: value)
         }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> HostStoreCallback {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: HostStoreCallback, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


