#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeProllyEngine: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = ProllyEngine

    public static func lift(_ handle: UInt64) throws -> ProllyEngine {
        return ProllyEngine(unsafeFromHandle: handle)
    }

    public static func lower(_ value: ProllyEngine) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ProllyEngine {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: ProllyEngine, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeProllyEngine_lift(_ handle: UInt64) throws -> ProllyEngine {
