public struct AuthenticatedProofBundleVerificationRecord: Equatable, Hashable {
    public var valid: Bool
    public var envelope: AuthenticatedProofEnvelopeVerificationRecord
    public var proof: ProofBundleVerificationRecord?
    public var proofError: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(valid: Bool, envelope: AuthenticatedProofEnvelopeVerificationRecord, proof: ProofBundleVerificationRecord?, proofError: String?) {
        self.valid = valid
        self.envelope = envelope
        self.proof = proof
        self.proofError = proofError
